79	// Reasoning handling mode (derived from R1-R3 comparisons)
80	enum class reasoning_mode {
81	    NONE,           // No reasoning markers detected
82	    TAG_BASED,      // Tag-based: <think>...</think> (start can be empty for delimiter-style)
83	    TOOLS_ONLY      // Only reason on tool calls, not on normal content
84	};
85	
86	inline std::ostream & operator<<(std::ostream & os, const reasoning_mode & mode) {
87	    switch (mode) {
88	        case reasoning_mode::NONE:
89	            return os << "NONE";
90	        case reasoning_mode::TAG_BASED:
91	            return os << "TAG_BASED";
92	        case reasoning_mode::TOOLS_ONLY:
93	            return os << "TOOLS_ONLY";
94	        default:
95	            return os << "UNKNOWN";
96	    }
97	}
