511	std::string common_chat_format_single(const struct common_chat_templates * tmpls,
512	                                      const std::vector<common_chat_msg> & past_msg,
513	                                      const common_chat_msg &              new_msg,
514	                                      bool                                 add_ass,
515	                                      bool                                 use_jinja) {
516	    common_chat_templates_inputs inputs;
517	    inputs.use_jinja = use_jinja;
518	    inputs.add_bos   = tmpls->add_bos;
519	    inputs.add_eos   = tmpls->add_eos;
520	
521	    std::string fmt_past_msg;
522	    if (!past_msg.empty()) {
523	        inputs.messages              = past_msg;
524	        inputs.add_generation_prompt = false;
525	        fmt_past_msg                 = common_chat_templates_apply(tmpls, inputs).prompt;
526	    }
527	    std::ostringstream ss;
528	    // if the past_msg ends with a newline, we must preserve it in the formatted version
529	    if (add_ass && !fmt_past_msg.empty() && fmt_past_msg.back() == '\n') {
530	        ss << "\n";
531	    };
532	    // format chat with new_msg
533	    inputs.messages.push_back(new_msg);
534	    inputs.add_generation_prompt = add_ass;
535	    auto fmt_new_msg             = common_chat_templates_apply(tmpls, inputs).prompt;
536	    // get the diff part
537	    ss << fmt_new_msg.substr(fmt_past_msg.size(), fmt_new_msg.size() - fmt_past_msg.size());
538	    return ss.str();
539	}
