// Jinja-based template representation
struct common_chat_template {
    jinja::program prog;           // Compiled Jinja program
    std::string bos_tok;          // Beginning of sequence token
    std::string eos_tok;          // End of sequence token
    std::string src;              // Original template source
    chat_template_caps caps;      // Template capabilities (e.g., supports_tools, supports_system_role)
};

// Handler parameters containing application inputs
struct common_chat_templates_inputs {
    std::vector<common_chat_msg> messages;
    std::string grammar;
    std::string json_schema;
    bool add_generation_prompt = true;
    bool use_jinja = true;
    std::vector<common_chat_tool> tools;
    common_chat_tool_choice tool_choice;
    bool parallel_tool_calls = false;
    // ... and other parameters
};

// Handler output parameters
struct common_chat_params {
    common_chat_format format;     // Parsing format (CONTENT_ONLY, PEG_SIMPLE, PEG_NATIVE, PEG_GEMMA4)
    std::string prompt;            // Formatted prompt
    std::string grammar;           // Generated grammar
    bool supports_thinking = false;
    std::string thinking_start_tag;
    std::string thinking_end_tag;
    std::vector<std::string> preserved_tokens;
    std::vector<common_grammar_trigger> grammar_triggers;
    std::string parser;            // Serialized PEG parser definition
};

// Template manager holding both default and tool-use variants
struct common_chat_templates {
    bool add_bos;
    bool add_eos;
    bool has_explicit_template;
    std::unique_ptr<common_chat_template> template_default;
